class Solution:
    def isStrictlyPalindromic(self, n):
        def to_base(x, b):
            digits = []
            while x > 0:
                digits.append(x % b)
                x //= b
            return digits
        for b in range(2, n - 1):
            d = to_base(n, b)
            if d != d[::-1]:
                return False
        return True

