var isStrictlyPalindromic = function(n) {
    const rep = [];
    let x = n;
    const b = n - 2;
    while (x > 0) {
        rep.push(x % b);
        x = Math.floor(x / b);
    }
    for (let i = 0, j = rep.length - 1; i < j; i++, j--) {
        if (rep[i] !== rep[j]) return false;
    }
    return true;
};
